import{_ as o,o as l,c,ak as d}from"./chunks/framework.Cr45f4vL.js";const p=JSON.parse('{"title":"HarukiBot 使用指南","description":"","frontmatter":{},"headers":[],"relativePath":"help/haruki/index.md","filePath":"doc/help/haruki/index.md"}'),i={name:"help/haruki/index.md"};function t(a,e,r,s,n,k){return l(),c("div",null,[...e[0]||(e[0]=[d('<h1 id="harukibot-使用指南" tabindex="-1">HarukiBot 使用指南 <a class="header-anchor" href="#harukibot-使用指南" aria-label="Permalink to “HarukiBot 使用指南”">​</a></h1><div class="info custom-block"><p class="custom-block-title">使用须知</p><p>HarukiBot 指令<strong>不需要</strong> <code>@mzkbot</code> 前缀，直接发送即可。</p></div><h2 id="pjsk歌曲信息相关查询" tabindex="-1">PJSK歌曲信息相关查询 <a class="header-anchor" href="#pjsk歌曲信息相关查询" aria-label="Permalink to “PJSK歌曲信息相关查询”">​</a></h2><h3 id="pjskinfo" tabindex="-1">pjskinfo <a class="header-anchor" href="#pjskinfo" aria-label="Permalink to “pjskinfo”">​</a></h3><ul><li><code>pjskinfo&lt;曲名&gt;</code>, <code>song&lt;曲名&gt;</code>, <code>musicinfo&lt;曲名&gt;</code> 查看当前歌曲详细信息</li><li><code>pjskbpm&lt;曲名&gt;</code> 查看当前歌曲的bpm</li><li><code>查bpm&lt;数字&gt;</code> 查询对应bpm所有歌曲</li></ul><h3 id="谱面预览" tabindex="-1">谱面预览 <a class="header-anchor" href="#谱面预览" aria-label="Permalink to “谱面预览”">​</a></h3><ul><li><code>谱面预览 &lt;曲名&gt; &lt;难度&gt;</code> 查询对应曲名，难度的谱面预览（来源：<a href="https://pjsekai.moe/" target="_blank" rel="noreferrer">ぷろせかもえ！</a>） <ul><li><code>难度</code>支持的输入: <code>easy</code>, <code>normal</code>, <code>hard</code>, <code>expert</code>, <code>master</code>, <code>append</code>, <code>ez</code>, <code>nm</code>, <code>hd</code>, <code>ex</code>, <code>ma</code>, <code>ap</code>, <code>apd</code></li><li>如果查询<code>master</code>可省略难度</li></ul></li></ul><h3 id="昵称设置" tabindex="-1">昵称设置 <a class="header-anchor" href="#昵称设置" aria-label="Permalink to “昵称设置”">​</a></h3><ul><li><code>musicset&lt;昵称&gt;to&lt;歌名&gt;</code> 设置歌曲昵称</li><li><code>musicdel&lt;昵称&gt;</code> 删除歌曲昵称</li><li><code>charalias&lt;昵称&gt;</code> 查看特定角色所有昵称</li><li><code>charaset&lt;昵称&gt;to&lt;角色名(可以是现有昵称)&gt;</code> 设置角色群通用昵称,如<code>charasetkndto宵崎奏</code></li><li><code>charadel&lt;昵称&gt;</code> 删除角色群通用昵称</li><li><code>grcharaset&lt;新昵称&gt;to&lt;已有昵称&gt;</code> 设置仅当前群可用角色昵称</li><li><code>grcharadel&lt;已有昵称&gt;</code> 删除仅当前群可用角色昵称</li><li>[后续将会添加]<code>charainfo&lt;昵称&gt;</code> 查看该角色的个人资料</li></ul><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>所有歌曲昵称设置，角色昵称设置的日志内容将会在实时日志页面按日公示。<br> 若违反相关条例将会视情况采取删除对应昵称至禁止使用Bot不等的措施。</p></div><h2 id="查询玩家信息" tabindex="-1">查询玩家信息 <a class="header-anchor" href="#查询玩家信息" aria-label="Permalink to “查询玩家信息”">​</a></h2><blockquote><p>在命令前加<code>en</code>即可查询国际服信息，如<code>en绑定</code>, <code>ensk</code>, <code>en逮捕</code>, <code>enpjskprofile</code></p></blockquote><blockquote><p>在命令前加<code>tw</code>即可查询台服信息，如<code>tw绑定</code>, <code>twsk</code>, <code>tw逮捕</code>, <code>twpjskprofile</code></p></blockquote><blockquote><p>在命令前加<code>kr</code>即可查询韩服信息，如<code>kr绑定</code>, <code>krsk</code>, <code>kr逮捕</code>, <code>krpjskprofile</code></p></blockquote><blockquote><p>在命令前加<code>cn</code>即可查询国服信息，如<code>cn绑定</code>, <code>cnsk</code>, <code>cn逮捕</code>, <code>cnpjskprofile</code></p></blockquote><ul><li><code>绑定+id</code> 通过游戏uid绑定你的游戏账号</li></ul><h2 id="mysekai相关查询" tabindex="-1">MySekai相关查询 <a class="header-anchor" href="#mysekai相关查询" aria-label="Permalink to “MySekai相关查询”">​</a></h2><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>Android 用户建议使用 <a href="https://haruki.seiunx.com/upload_mysekai" target="_blank" rel="noreferrer">Haruki工具箱-上传MySekai数据</a> 的<code>引继信息上传模式</code><br> iOS / iPadOS 用户 建议使用代理工具MitM模块更新，要求如下:</p><ul><li>拥有代理工具 ( 如 Shadowrocket / Quantumult X / Surge / Loon / Stash )</li><li>有需要请加群<strong>1026390204</strong>咨询群友</li></ul></div><ul><li><code>mysekai_analyze</code>、<code>mysekai分析</code>、<code>ms分析</code>、<code>msa</code> 根据用户上传至Haruki数据库的数据分析MySekai现存材料</li><li><code>mysekai_analyze2</code>、<code>mysekai分析2</code>、<code>ms分析2</code>、<code>msa2</code> 根据用户上传至Haruki数据库的数据分析MySekai现存材料 (新版UI设计，感谢Foglio的设计)</li><li><code>mysekai_maps</code>、<code>msm</code>、<code>mysekai地图</code>、<code>ms地图</code> 根据用户上传至Haruki数据库的数据生成资源分布图 ( 感谢原作者<a href="https://github.com/MiddleRed" target="_blank" rel="noreferrer">中红(MiddleRed)</a> 以及移植作者<a href="https://github.com/NeuraXmy" target="_blank" rel="noreferrer">ルナ茶(NeuraXmy)</a>的贡献 )</li></ul><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>mysekai_maps指令后面添加数字可以查询单图地图</p><ul><li>数字1: 草原</li><li>数字2: 花田</li><li>数字3: 沙滩</li><li>数字4: 废墟</li></ul></div><ul><li><code>mysekai照片 + 序号</code>、<code>ms照片 + 序号</code>、<code>msp + 序号</code> 根据用户上传到Haruki数据库的数据下载用户在MySekai里面拍摄的照片 (按拍摄顺序)</li></ul><h2 id="活动排名相关查询" tabindex="-1">活动排名相关查询 <a class="header-anchor" href="#活动排名相关查询" aria-label="Permalink to “活动排名相关查询”">​</a></h2><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>目前HarukiBot的活动排名相关功能具有如下新特性:</p><ul><li>对于<code>日服</code>、<code>国服</code>: T10数据采集精度为<strong>10秒</strong>，T11到T100数据采集精度为<strong>1分钟</strong></li><li>对于<code>台服</code>: T10数据采集精度为<strong>30秒</strong>，T11到T100数据采集精度为<strong>1分钟</strong></li><li>对于<code>韩服</code>、<code>国际服</code>: 由于使用人数较少，T100数据采集精度统一为<strong>1分钟</strong></li></ul></div><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>以下指令添加<code>wl</code>前缀可以查询World Link活动单榜的排名和分数<br> 指令最后添加<code>-c &lt;角色别名&gt;</code>可以获取特定角色单榜的排名和分数，不添加则获取<strong>目前正在进行的</strong>单榜排名和分数。 例子如下:</p><ul><li><code>wlsk 100</code> 获取<strong>目前</strong>单榜的100名的排名和分数</li><li><code>wlsk 100 -c haruka</code> 获取<strong>桐谷遥</strong>单榜的100名的排名和分数</li></ul></div><ul><li><code>sk</code> 如果你在前100，可以用该命令查询排名和分数</li><li><code>sk &lt;游戏数字id&gt;</code> 查询特定游戏玩家的排名和分数</li><li><code>sk &lt;排名&gt;</code> 查询特定排名玩家的排名与分数，支持同时查询最多7个玩家</li><li><code>查房 &lt;排名&gt;</code>, <code>cf &lt;排名&gt;</code> 查询特定排名最近1小时相关信息</li><li><code>sk线</code>, 查询榜线分数</li><li><code>时速</code> 查看近一小时各榜线的PT增长速度</li><li><code>半日速</code> 查看近半天各榜线的PT增长速度</li><li><code>日速</code> 查看近一天各榜线的PT增长速度</li></ul><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p><code>时速</code>、<code>半日速</code>、<code>日速</code>指令后面可以跟数字，将特定时间范围内的PT增长转换为对应速度<br> 如<code>时速10</code> = 10分钟内PT增长量转换的时速<br> 可输入数字单位为分钟，最大不超过1440分钟(即一天)</p></div><ul><li><code>分数线 &lt;排名&gt;</code>、<code>rtr &lt;排名&gt;</code> 查看本期活动中特定排名的分数趋势</li><li><code>追踪</code>、<code>ptr</code> 追踪<strong>自己</strong>在本期活动中的活动PT趋势与活动排名趋势</li><li><code>追踪 &lt;排名&gt;</code>、<code>ptr &lt;排名&gt;</code> 追踪<strong>目前特定排名</strong>在本期活动中的活动PT趋势与活动排名趋势</li></ul><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p><code>追踪</code>指令支持双排名查询<br> 如<code>追踪1 2</code>会对比目前排名为1和2的两个玩家的活动PT趋势和活动排名趋势</p></div><ul><li>[后续将会添加]<code>sk预测</code> 查看预测线，预测信息来自<a href="https://3-3.dev/" target="_blank" rel="noreferrer">3-3.dev</a>（仅日服）</li></ul><h2 id="打歌情况相关查询" tabindex="-1">打歌情况相关查询 <a class="header-anchor" href="#打歌情况相关查询" aria-label="Permalink to “打歌情况相关查询”">​</a></h2><ul><li><code>逮捕@[xxx]</code> 如果此人绑定过id，就可以看TA的ex与master难度fc、ap数，排位信息(后续将会添加)</li><li><code>逮捕+id</code> 查看对应id的expert难度、master难度、append难度的fc、ap数，排位信息(后续将会添加)</li><li><code>pjskprofile</code>, <code>个人信息</code> 生成绑定id的profile图片</li></ul><h2 id="隐私相关指令" tabindex="-1">隐私相关指令 <a class="header-anchor" href="#隐私相关指令" aria-label="Permalink to “隐私相关指令”">​</a></h2><ul><li><code>不给看</code> 不允许他人逮捕自己，但自己还是可以逮捕自己，使用sk查分和逮捕自己时不会显示游戏uid</li><li><code>给看</code> 允许他人逮捕自己</li></ul><h2 id="卡牌及活动信息相关查询" tabindex="-1">卡牌及活动信息相关查询 <a class="header-anchor" href="#卡牌及活动信息相关查询" aria-label="Permalink to “卡牌及活动信息相关查询”">​</a></h2><blockquote><p>查卡面/查活动功能为 <a href="https://github.com/cYanosora" target="_blank" rel="noreferrer">Yozora</a> 所写，非常感谢</p></blockquote><ul><li><code>查卡/查卡面/查询卡面/findcard [角色昵称]</code>: 获取当前角色所有卡牌</li><li><code>查卡/查卡面/查询卡面/cardinfo [卡面id]</code>: 获取卡牌id详细卡面信息</li><li><code>查活动/查询活动/event [活动id]</code>: 查看指定活动信息（可直接使用<code>event</code>查看当前活动信息）</li><li><code>查活动/查询活动/findevent [关键字]</code>: 通过关键字筛选活动，返回活动概要图，没有关键字则会返回提示图 <ul><li>单关键字方式： <ul><li>查活动 5v5：返回活动类型为5v5的活动概要</li><li>查活动 紫月：返回活动属性为紫月的活动概要</li><li>查活动 knd：返回当期出卡(包括报酬)含knd的活动概要</li><li>查活动 miku：返回当期出卡含任意组合的miku的活动概要</li><li>查活动 25miku：返回当期出卡含白葱的活动概要</li><li>查活动 25h：返回当期出卡含任意25成员(不含vs)的活动概要，而并不是25箱活的活动概要</li></ul></li><li>多关键字方式： <ul><li>查活动 草 5v5：返回活动类型为5v5，活动属性为绿草的活动概要</li><li>查活动 knd 蓝：返回活动属性为蓝星，出卡含knd的活动概要</li><li>查活动 普活 紫月 knd：返回活动类型为马拉松，活动属性为紫月，出卡含knd的活动概要(即使knd为不同属性的报酬卡，也会显示)</li></ul></li><li>使用例： <ul><li>查活动 25h：仅返回25箱活的活动概要</li><li>查活动 25h 25miku：返回25箱活且vs出卡为白葱的活动概要</li><li>查活动 knd ick：返回出卡同时包括knd、ick混活的活动概要</li></ul></li></ul></li><li><code>活动图鉴/活动列表/活动总览/findevent all</code>: 返回当前所有活动的概要，该功能由于图片过大无法在频道bot使用</li></ul>',36)])])}const h=o(i,[["render",t]]);export{p as __pageData,h as default};
